&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;92 : 115&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rarr; &lt;/span&gt;&lt;span class=&quot;math-tex&quot;&gt;\({92 {} \over 115}\)&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt; = &lt;/span&gt;&lt;span class=&quot;math-tex&quot;&gt;\({4 {} \over 5}\)&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;अतः, &lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;quot;विकल्प 3&amp;quot;&lt;/span&gt; सही उत्तर है।&lt;/p&gt;

